// Verifica o que precisa postar AMANHÃ
const hoje = new Date();
const amanha = new Date(hoje.getTime() + 24 * 60 * 60 * 1000);
const diaSemana = amanha.getDay(); // 0=Dom, 1=Seg, ..., 6=Sab

// Mapeamento do cronograma
const agenda = {
  0: null, // Domingo — opcional stories bastidores
  1: { formato: '📊 Carrossel', hora: '7h30', pilar: 'Educação', desc: 'Carrossel educativo — tema da semana' },
  2: { formato: '🎬 Reels', hora: '19h00', pilar: 'Urgência', desc: 'Reels de urgência/case — tema da semana' },
  3: { formato: '📲 Stories', hora: '12h00', pilar: 'Engajamento', desc: 'Stories com enquete ou quiz sobre NR-1' },
  4: { formato: '📊 Carrossel', hora: '18h00', pilar: 'Solução', desc: 'Carrossel checklist ou erros comuns' },
  5: { formato: '🎬 Reels', hora: '7h30', pilar: 'Autoridade', desc: 'Reels com Guilherme — autoridade e solução' },
  6: { formato: '📷 Feed Foto', hora: '10h00', pilar: 'Autoridade', desc: 'Foto + quote empresarial (navy/dourado)' }
};

const postagem = agenda[diaSemana];
const nomesDia = ['Domingo','Segunda','Terça','Quarta','Quinta','Sexta','Sábado'];
const nomeAmanha = nomesDia[diaSemana];
const dataStr = amanha.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });

if (!postagem) {
  // Domingo — lembrete leve
  const msg = `📲 AMANHÃ É DOMINGO (${dataStr})\n\nNenhuma postagem obrigatória.\n✅ Opcional: Stories de bastidores ("por trás do método") às 16h.\n\nDescanse e prepare a semana! 💪`;
  return [{ json: { mensagem: msg } }];
}

let msg = `⏰ AMANHÃ: ${nomeAmanha} ${dataStr}\n\n`;
msg += `${postagem.formato} às ${postagem.hora}\n`;
msg += `Pilar: ${postagem.pilar}\n`;
msg += `Tema: ${postagem.desc}\n\n`;

// Checklist por formato
if (postagem.formato.includes('Carrossel')) {
  msg += `✅ Checklist:\n`;
  msg += `□ Slides criados no Canva (5–8 slides)\n`;
  msg += `□ Slide 1: gancho forte\n`;
  msg += `□ Último slide: CTA (eBook ou Grupo WA)\n`;
  msg += `□ Legenda da postagem escrita\n`;
  msg += `□ Hashtags preparadas (máx 10)\n`;
} else if (postagem.formato.includes('Reels')) {
  msg += `✅ Checklist:\n`;
  msg += `□ Roteiro gravado / filmado\n`;
  msg += `□ Editado no CapCut (30–60s)\n`;
  msg += `□ Legendas automáticas adicionadas\n`;
  msg += `□ Áudio/música ajustados\n`;
  msg += `□ Thumbnail definida\n`;
  msg += `□ Legenda + CTA escrita\n`;
} else if (postagem.formato.includes('Stories')) {
  msg += `✅ Checklist:\n`;
  msg += `□ 3–5 stories planejados\n`;
  msg += `□ Enquete ou quiz criado\n`;
  msg += `□ Link do eBook/WA no último story\n`;
} else if (postagem.formato.includes('Foto')) {
  msg += `✅ Checklist:\n`;
  msg += `□ Foto selecionada ou criada\n`;
  msg += `□ Arte finalizada (1080x1080 ou 1080x1350)\n`;
  msg += `□ Legenda com quote escrita\n`;
  msg += `□ CTA no final da legenda\n`;
}

msg += `\n💡 Tudo pronto? Agende para ${postagem.hora} no Meta Business Suite.`;

return [{ json: { mensagem: msg } }];
